import{_ as t,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"15. Managing Conduct And Performance","description":"","frontmatter":{"title":"15. Managing Conduct And Performance","eba":"Nurses and Midwives 2024-2028","topics":["consultation","disputes","discipline","union-matters"]},"headers":[],"relativePath":"ebas/nurses-midwives/consultation-disputes/15-managing-conduct-and-performance.md","filePath":"ebas/nurses-midwives/consultation-disputes/15-managing-conduct-and-performance.md"}'),i={name:"ebas/nurses-midwives/consultation-disputes/15-managing-conduct-and-performance.md"};function s(a,e,p,c,l,d){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_15-managing-conduct-and-performance" tabindex="-1">15. Managing Conduct And Performance <a class="header-anchor" href="#_15-managing-conduct-and-performance" aria-label="Permalink to &quot;15. Managing Conduct And Performance&quot;">​</a></h1><p><strong>15.1</strong> Application</p><p><strong>(a)</strong> Except as provided at subclause 15.1(e), where an Employer has concerns about:</p><p><strong>(i)</strong> the Conduct of an Employee; or</p><p><strong>(ii)</strong> a performance issue that may constitute Misconduct,</p><p>the following procedure will apply.</p><p><strong>(b)</strong> There are two steps in a disciplinary process under this clause as follows:</p><p><strong>(i)</strong> investigative procedure; and</p><p><strong>(ii)</strong> disciplinary procedure.</p><p><strong>(c)</strong> An Employee will be provided a reasonable opportunity to be represented at any time (including by a Union) with respect to all matters set out in this clause.</p><p><strong>(d)</strong> The Employer will notify the Employee in accordance with subclause 15.3(b) as soon as practicable following the Employer becoming aware of the alleged concerns at subclause 15.1(a).</p><p><strong>(e)</strong> Exception - Employees who have not completed a minimum period of employment with their Employer</p><p>Where an Employee has not completed a period of employment with their Employer of at least the minimum employment period defined at section 383 of the Act, and the Employer is considering the termination of the Employee&#39;s employment, the Employer will:</p><p><strong>(i)</strong> provide the concerns in writing to the Employee as soon as practicable following the Employer becoming aware of the alleged concerns;</p><p><strong>(ii)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(iii)</strong> other than in the case of Serious Misconduct, provide the Employee with an opportunity to improve their Performance or Conduct;</p><p><strong>(iv)</strong> meet with the Employee (and, where relevant, their representative); and</p><p><strong>(v)</strong> consider any explanation by the Employee including any matters raised in mitigation before making a decision to terminate the employment.</p><p>The terms of clauses 15.3 to 15.5 inclusive do not apply to Employees within the scope of the exception in this subclause 15.1(e).</p><p><strong>15.2</strong> Definitions</p><p><strong>(a)</strong> Conduct means the manner in which the Employee&#39;s behaviour impacts on their work.</p><p><strong>(b)</strong> Misconduct means an Employee&#39;s intentional or negligent failure to abide by or adhere to the standards of conduct expected by the Employer. A performance issue can be considered misconduct where, despite all reasonably practicable interventions by the Employer, the Employee is unable to fulfil all or part of their job requirements to a satisfactory level.</p><p><strong>(c)</strong> Performance means the manner in which the Employee fulfils their job requirements. The level of performance is determined by reference to an</p><p>Employee&#39;s knowledge, skills, qualifications, abilities and the requirements of the role.</p><p><strong>(d)</strong> Serious Misconduct is as defined under the Act and is both wilful and deliberate. Currently the Act defines serious misconduct, in part, as:</p><p><strong>(i)</strong> wilful or deliberate behaviour by an Employee that is inconsistent with the continuation of the contract of employment;</p><p><strong>(ii)</strong> conduct that causes serious and imminent risk to:</p><p><strong>(A)</strong> the health or safety of a person; or</p><p><strong>(B)</strong> the reputation, viability or profitability of the employer&#39;s business.</p><p>Conduct that is serious misconduct includes each of the following:</p><p><strong>(iii)</strong> the Employee, in the course of the Employee&#39;s employment, engaging in:</p><p><strong>(A)</strong> theft;</p><p><strong>(B)</strong> fraud;</p><p><strong>(C)</strong> assault; or</p><p><strong>(D)</strong> sexual harassment;</p><p><strong>(iv)</strong> the Employee being intoxicated at work;</p><p><strong>(v)</strong> the Employee refusing to carry out a lawful and reasonable instruction that is consistent with the Employee&#39;s contract of employment.</p><p>Subclauses 15.2(d)(iii)-15.2(d)(v) do not apply if the Employee is able to show that, in the circumstances, the conduct engaged in by the Employee was not conduct that made employment in the period of notice unreasonable.</p><p><strong>15.3</strong> Investigative procedure</p><p><strong>(a)</strong> The purpose of an investigative procedure is to conclude whether, on balance, concerns regarding Conduct or Performance are well-founded and supported by evidence. An investigation procedure must be fair including proper regard to procedural fairness.</p><p><strong>(b)</strong> The Employer will:</p><p><strong>(i)</strong> advise the Employee of the concerns and allegations in writing;</p><p><strong>(ii)</strong> provide the Employee with any material which forms the basis of the concerns, including statements (if any) it has at that time, before seeking a response;</p><p><strong>(iii)</strong> ensure the Employee is provided a reasonable opportunity to answer any concerns including a reasonable time to respond;</p><p><strong>(iv)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(v)</strong> ensure that the reason for any interview is explained; and</p><p><strong>(vi)</strong> take reasonable steps to investigate the Employee&#39;s response.</p><p><strong>(c)</strong> Where the Employer has complied with subclause 15.3(b)(i)-(iv) and the Employee does not dispute the concerns, the Employee may opt to decline the opportunity to be interviewed.</p><p><strong>(d)</strong> Where the Employee opts to decline the opportunity to be interviewed, the Employee may still raise matters under subclause 15.4(c) including matters in mitigation if a disciplinary procedure (see clause 15.4) is proposed.</p><p><strong>15.4</strong> Procedure to address poor Performance or Misconduct</p><p><strong>(a)</strong> The procedure applies if, following the investigation, the Employer reasonably considers that the Employee&#39;s Conduct or Performance may warrant disciplinary steps being taken.</p><p><strong>(b)</strong> The Employer will:</p><p><strong>(i)</strong> notify the Employee in writing of the outcome of the investigation process, including the basis of any conclusion; and</p><p><strong>(ii)</strong> provide the Employee with a reasonable opportunity to provide information about the matters in 15.4(c).</p><p><strong>(c)</strong> In considering whether to take disciplinary action, the Employer will consider:</p><p><strong>(i)</strong> whether there is a valid reason related to the Conduct or Performance of the Employee arising from the investigation justifying disciplinary action;</p><p><strong>(ii)</strong> whether the Employee knew or ought to have known that the Conduct or Performance was below acceptable standards; and</p><p><strong>(iii)</strong> any explanation by the Employee relating to Conduct including any matters raised in mitigation.</p><p><strong>(d)</strong> The Employer will ensure that any disciplinary action being considered under subclause 15.5(a) below arising from an investigation relating to the professional conduct of a nurse or midwife, will be informed by someone with a thorough understanding of applicable professional standards of practice issued by the Australian professional registration body.</p><p><strong>15.5</strong> Possible outcomes</p><p><strong>(a)</strong> Where it is determined that after following the procedures in this clause 15 that disciplinary action is warranted, the Employer may take any of the following steps depending on the seriousness of the Conduct or Performance and the steps shall be recorded on the Employee&#39;s personnel file:</p><p><strong>(i)</strong> where the Performance or Conduct issue does not constitute Serious Misconduct:</p><p><strong>(A)</strong> counsel the Employee;</p><p><strong>(B)</strong> give the Employee a first written warning;</p><p><strong>(C)</strong> give the Employee a second written warning in the event that the Employee has previously been given a first written</p><p>warning within the previous 12 months for that course of Conduct;</p><p><strong>(D)</strong> give the Employee a final written warning in the event that the Employee has previously been given a second written warning within the preceding 18 month period for that course of Conduct; or</p><p><strong>(E)</strong> terminate the Employee&#39;s employment on notice in the case of an Employee who repeats a course of Conduct for which a final warning was given in the preceding 18 months; or</p><p><strong>(ii)</strong> where the Performance or Conduct issue does constitute Serious Misconduct:</p><p><strong>(A)</strong> terminate the Employee&#39;s employment without notice; or</p><p><strong>(B)</strong> alternatively, issue the Employee with a final warning without following the steps in subclause 15.5(a)(i) above.</p><p><strong>(b)</strong> The Employer&#39;s decision and a summary of its reasons will be notified to the Employee in writing.</p><p><strong>(c)</strong> If after any warning or counselling, a period of 12 or 18 months elapses (as relevant) without the Employee repeating a course of Conduct for which the preceding warning or counselling was given, the Employer cannot rely on the preceding warning or counselling for the purpose of issuing a further warning.</p><p><strong>15.6</strong> Disputes</p><p>A dispute over this clause (including clause 15.7) is to be dealt with in accordance with the Dispute Resolution Procedure of this Agreement.</p><p><strong>15.7</strong> Performance Management</p><p><strong>(a)</strong> Nothing in this clause 15 will prevent the Employer from undertaking performance management to support Employees.</p><p><strong>(b)</strong> In this clause 15, performance management includes reasonable actions to address performance by identifying performance deficits, the Employer&#39;s expected outcomes and performance measures, and strategies to meet those measures including the provision of support and education the Employee may reasonably require. Performance management measures may be included in a performance improvement plan that seeks to address the identified deficits and/or describe the matters which require improvement within a time period that is reasonable in the circumstances.</p><p><strong>(c)</strong> In this clause 15, performance management does not include sanctions in addition to those set out at clause 15.5 above.</p><p>Plain language terms: performance management, disciplinary, misconduct, PIP, performance improvement.</p>',80)])])}const m=t(i,[["render",s]]);export{h as __pageData,m as default};
